import{_ as a,p as e,q as s,a1 as n}from"./framework-5866ffd3.js";const d={},r=n(`<h1 id="dpkg-statoverride" tabindex="-1"><a class="header-anchor" href="#dpkg-statoverride" aria-hidden="true">#</a> dpkg-statoverride</h1><p>Debian Linux中覆盖文件的所有权和模式</p><h2 id="补充说明" tabindex="-1"><a class="header-anchor" href="#补充说明" aria-hidden="true">#</a> 补充说明</h2><p><strong>dpkg-statoverride命令</strong> 用于Debian Linux中覆盖文件的所有权和模式，让dpkg于包安装时使得文件所有权与模式失效。</p><h3 id="语法" tabindex="-1"><a class="header-anchor" href="#语法" aria-hidden="true">#</a> 语法</h3><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>dpkg-statoverride<span class="token punctuation">(</span>选项<span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h3 id="选项" tabindex="-1"><a class="header-anchor" href="#选项" aria-hidden="true">#</a> 选项</h3><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>-add：为文件添加一个改写；
--remove：为文件删除一个改写；
--list：显示所有改写列表；
--update：如果文件存在，则立刻执行改写操作。
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="实例" tabindex="-1"><a class="header-anchor" href="#实例" aria-hidden="true">#</a> 实例</h3><p>修改文件夹的权限属性：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">sudo</span> dpkg-statoverride <span class="token parameter variable">--update</span> <span class="token parameter variable">--add</span> nagios nagios <span class="token number">751</span> /var/lib/nagios3
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>强制修改文件夹的权限属性：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">sudo</span> dpkg-statoverride <span class="token parameter variable">--force</span> <span class="token parameter variable">--update</span> <span class="token parameter variable">--add</span> root sasl <span class="token number">755</span> /var/spool/postfix/var/run/saslauthd
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>将文件从数据库中删除：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">sudo</span> dpkg-statoverride <span class="token parameter variable">--remove</span> /usr/bin/wall
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div>`,15),i=[r];function t(l,o){return e(),s("div",null,i)}const p=a(d,[["render",t],["__file","dpkg-statoverride.html.vue"]]);export{p as default};
